const fs = require('fs');
const path = require('path');

function readLogFile(filename) {
  const sanitizedFilename = path.basename(filename);
  const filePath = path.join(__dirname, 'logs', sanitizedFilename);

  try {
    const data = fs.readFileSync(filePath, 'utf-8');
    return data;
  } catch (err) {
    throw new Error(`Error reading log file: ${err}`);
  }
}